import pandas as pd
import matplotlib.pyplot as plt

# Load the data generated by test_performance.cpp
try:
    data = pd.read_csv('performance_results.csv')
except FileNotFoundError:
    print("Error: 'performance_results.csv' not found. Run your C++ benchmark first.")
    exit()

# Set up the plot
plt.figure(figsize=(10, 6))

# Plot both lines
plt.plot(data['Run'], data['AES_Time_ms'], label='AES-128-CBC (Symmetric)', color='blue', linewidth=2)
plt.plot(data['Run'], data['RSA_Time_ms'], label='RSA-3072 OAEP (Asymmetric)', color='red', linewidth=2)

# Add titles and labels
plt.title('Cryptography Performance: AES vs RSA (1KB File Transfer)', fontsize=14)
plt.xlabel('Run Number', fontsize=12)
plt.ylabel('Total Time (Milliseconds)', fontsize=12)

# Improve visibility
plt.grid(True, linestyle='--', alpha=0.7)
plt.legend(fontsize=12)

# Save and show
plt.tight_layout()
plt.savefig('performance_plot.png', dpi=300)
print("Plot saved as 'performance_plot.png'")
plt.show()